import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/RecordingIndicators.css';

function RecordingIndicators() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [indicatorsData, setIndicatorsData] = useState([]);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    fetchRecords();
  }, []);

  const fetchRecords = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    try {
      const response = await fetch(`http://localhost:5000/api/health-records/${user_id}`);
      if (!response.ok) {
        throw new Error('Failed to fetch records');
      }
      const data = await response.json();
      setIndicatorsData(data);
    } catch (error) {
      console.error('Error fetching records:', error);
      setError('Failed to load records');
    }
  };

  const handleInputChange = async (recordId, field, value) => {
    const numericFields = ['FEV1', 'FVC', 'PEF', 'respiratory_rate', 'pulse', 'cough', 
      'breathlessness', 'wheezing', 'chest_tightness', 'nighttime_awakenings'];

    let processedValue = value;
    if (value === '') {
      processedValue = 0;
    } else if (numericFields.includes(field)) {
      processedValue = Number(value);
      if (isNaN(processedValue)) {
        setError(`Invalid numeric value for ${field}`);
        setTimeout(() => setError(''), 2000);
        return;
      }
    }

    const currentRecord = indicatorsData.find(record => record.id === recordId);
    if (!currentRecord) {
      setError('Record not found');
      return;
    }

    const updatedRecord = {
      ...currentRecord,
      [field]: processedValue
    };

    try {
      const response = await fetch(`http://localhost:5000/api/update-health-record/${recordId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(updatedRecord),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to update record');
      }

      await fetchRecords();
      setSuccess('Record updated');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      console.error('Error updating record:', err);
      setError(err.message || 'Failed to update record');
      setTimeout(() => setError(''), 2000);
    }
  };

  const handleAddNewRow = async () => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    const emptyRecord = {
      user_id: parseInt(user_id),
      date: new Date().toISOString().split('T')[0],
      FEV1: 0,
      FVC: 0,
      PEF: 0,
      respiratory_rate: 0,
      pulse: 0,
      cough: 0,
      breathlessness: 0,
      wheezing: 0,
      chest_tightness: 0,
      nighttime_awakenings: 0,
      medicine: ''
    };

    try {
      const response = await fetch('http://localhost:5000/api/health-records', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(emptyRecord),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to create record');
      }

      await fetchRecords();
      setSuccess('New record added');
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      console.error('Error creating record:', err);
      setError(err.message || 'Failed to create record');
      setTimeout(() => setError(''), 2000);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  return (
    <div className={`recording-indicators-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
          <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>
      <div className="content">
        <h2>Recording Indicators</h2>
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}

        <div className="table-container">
          <table className="indicators-table">
            <thead>
              <tr>
                <th>Date</th>
                <th>FEV1</th>
                <th>FVC</th>
                <th>PEF</th>
                <th>Respiratory Rate</th>
                <th>Pulse</th>
                <th>Cough</th>
                <th>Breathlessness</th>
                <th>Wheezing</th>
                <th>Chest Tightness</th>
                <th>Nighttime Awakenings</th>
                <th>Medicine</th>
              </tr>
            </thead>
            <tbody>
              {indicatorsData.map((row) => (
                <tr key={row.id}>
                  <td>
                    <input
                      type="date"
                      value={row.date ? row.date.split('T')[0] : ''}
                      onChange={(e) => handleInputChange(row.id, 'date', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      value={row.FEV1 || ''}
                      onChange={(e) => handleInputChange(row.id, 'FEV1', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      step="0.1"
                      value={row.FVC || ''}
                      onChange={(e) => handleInputChange(row.id, 'FVC', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.PEF || ''}
                      onChange={(e) => handleInputChange(row.id, 'PEF', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.respiratory_rate || ''}
                      onChange={(e) => handleInputChange(row.id, 'respiratory_rate', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      value={row.pulse || ''}
                      onChange={(e) => handleInputChange(row.id, 'pulse', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="3"
                      value={row.cough || ''}
                      onChange={(e) => handleInputChange(row.id, 'cough', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.breathlessness || ''}
                      onChange={(e) => handleInputChange(row.id, 'breathlessness', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.wheezing || ''}
                      onChange={(e) => handleInputChange(row.id, 'wheezing', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      max="1"
                      value={row.chest_tightness || ''}
                      onChange={(e) => handleInputChange(row.id, 'chest_tightness', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="number"
                      min="0"
                      value={row.nighttime_awakenings || ''}
                      onChange={(e) => handleInputChange(row.id, 'nighttime_awakenings', e.target.value)}
                    />
                  </td>
                  <td>
                    <input
                      type="text"
                      value={row.medicine || ''}
                      onChange={(e) => handleInputChange(row.id, 'medicine', e.target.value)}
                    />
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <button onClick={handleAddNewRow} className="add-row-button">
          Add New Row
        </button>
      </div>

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

